<template><view class="page"><view class="row"><view class="title">任务中心</view><view class="tag">小鱼干 {{balance}}</view></view><AppCard v-for="x in items" :key="x.id" :title="x.title"><view>奖励 {{x.reward}} 小鱼干</view><button class="btn" :disabled="x.claimed" @click="claim(x.id)">{{x.claimed?'已领取':'领取奖励'}}</button></AppCard></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';const items=ref<any[]>([]),balance=ref(0);async function load(){items.value=await qingxierApi.tasks();balance.value=(await qingxierApi.balance()).balance}onShow(load);async function claim(id:string){await qingxierApi.claimTask(id);await load()}</script>
